```javascript
const chipsValue = ["a,1%", "b,1%"];
const updatedChips = chipsValue.map(item => {
  const [text, percentage] = item.split(',');
  return [text, parseInt(percentage)];
});
console.log(updatedChips); // [["a", 1], ["b", 1]]
```

